code = """import json
# Access the businesses from query 10
businesses_raw = locals()['var_functions.query_db:10']
if not isinstance(businesses_raw, list):
    with open(businesses_raw, 'r') as f:
        businesses_raw = json.load(f)
# Count businesses with either bike parking or business parking
# The attributes field contains string representations
import ast

def has_parking(attrs):
    if not attrs:
        return False
    # Check BikeParking attribute
    if 'BikeParking' in attrs:
        val = attrs['BikeParking']
        if isinstance(val, str):
            if val.lower() == 'true':
                return True
            elif val.lower() == 'false':
                pass
            else:
                # Might be a Python repr of bool
                try:
                    parsed = ast.literal_eval(val)
                    if parsed is True:
                        return True
                except:
                    pass
        elif val is True:
            return True
    
    # Check BusinessParking attribute - it's a string repr of dict
    if 'BusinessParking' in attrs:
        val = attrs['BusinessParking']
        if isinstance(val, str) and val != 'None':
            # Check if it's a dict repr
            if '{' in val:
                try:
                    parsed = ast.literal_eval(val)
                    if isinstance(parsed, dict):
                        # If any parking type is True
                        if any(parsed.get(k) for k in ['garage', 'street', 'validated', 'lot', 'valet']):
                            return True
                except:
                    pass
            # Could also be True directly
            elif val.lower() == 'true':
                return True
    
    return False

count = sum(1 for b in businesses_raw if has_parking(b.get('attributes', {})))
print('__RESULT__:')
print(json.dumps({
    'total_businesses_checked': len(businesses_raw),
    'businesses_with_parking': count,
    'sample_ids_with_parking': [b['business_id'] for b in businesses_raw if has_parking(b.get('attributes', {}))][:10]
}))"""

